MERGE INTO tb_assist_signature t1 USING (SELECT #{businessType} AS business_type, #{businessId} AS business_id FROM DUAL) t2 ON (t1.business_type = t2.business_type AND t1.business_id = t2.business_id )
WHEN NOT MATCHED THEN INSERT (business_type, business_id, signature,is_verify_sign, create_date, update_date) VALUES (#{businessType}, #{businessId}, #{signature},#{isVerifySign}, #{createDate}, #{updateDate})
WHEN MATCHED THEN UPDATE SET signature = #{signature},is_verify_sign = #{isVerifySign}, update_date = #{updateDate}

UPDATE tb_assist_signature
SET signature   = #{signature},
    is_verify_sign   = #{isVerifySign},
    update_date = #{updateDate}
WHERE business_type = #{businessType} AND business_id = #{businessId}
